<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no">
<title>مغامرة ناصر 3D</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { background: #000; overflow: hidden; font-family: Arial, sans-serif; }
  canvas { display: block; }
  #ui {
    position: fixed; top: 0; left: 0; right: 0;
    display: flex; justify-content: space-between; align-items: center;
    padding: 10px 15px;
    background: linear-gradient(180deg, rgba(0,0,0,0.7) 0%, transparent 100%);
    z-index: 10;
  }
  #score-box {
    background: rgba(255,200,0,0.2);
    border: 2px solid gold;
    border-radius: 12px;
    padding: 6px 14px;
    color: gold;
    font-size: 18px;
    font-weight: bold;
    text-shadow: 0 0 8px gold;
  }
  #health-box {
    display: flex; gap: 5px; align-items: center;
  }
  .heart { font-size: 22px; }
  #level-box {
    background: rgba(0,150,255,0.2);
    border: 2px solid #00aaff;
    border-radius: 12px;
    padding: 6px 14px;
    color: #00aaff;
    font-size: 16px;
    font-weight: bold;
  }
  /* Mobile Controls */
  #mobile-controls {
    position: fixed; bottom: 0; left: 0; right: 0;
    display: flex; justify-content: space-between; align-items: flex-end;
    padding: 15px 20px 25px;
    z-index: 10;
    pointer-events: none;
  }
  #dpad {
    display: grid;
    grid-template-columns: 55px 55px 55px;
    grid-template-rows: 55px 55px 55px;
    gap: 4px;
    pointer-events: all;
  }
  .dpad-btn {
    background: rgba(255,255,255,0.15);
    border: 2px solid rgba(255,255,255,0.4);
    border-radius: 12px;
    color: white;
    font-size: 22px;
    display: flex; align-items: center; justify-content: center;
    cursor: pointer;
    user-select: none;
    -webkit-user-select: none;
    transition: background 0.1s;
    touch-action: none;
  }
  .dpad-btn:active, .dpad-btn.pressed {
    background: rgba(255,255,255,0.4);
    border-color: gold;
  }
  .dpad-empty { background: transparent; border: none; }
  #action-btns {
    display: flex; flex-direction: column; gap: 10px; align-items: flex-end;
    pointer-events: all;
  }
  .action-btn {
    width: 65px; height: 65px;
    border-radius: 50%;
    border: 3px solid;
    font-size: 13px;
    font-weight: bold;
    color: white;
    cursor: pointer;
    user-select: none;
    -webkit-user-select: none;
    display: flex; align-items: center; justify-content: center;
    flex-direction: column;
    touch-action: none;
    transition: transform 0.1s;
  }
  .action-btn:active { transform: scale(0.9); }
  #btn-jump {
    background: rgba(0,200,100,0.3);
    border-color: #00cc66;
    box-shadow: 0 0 15px rgba(0,200,100,0.5);
  }
  #btn-attack {
    background: rgba(255,50,50,0.3);
    border-color: #ff3333;
    box-shadow: 0 0 15px rgba(255,50,50,0.5);
  }
  #btn-dash {
    background: rgba(100,100,255,0.3);
    border-color: #6666ff;
    box-shadow: 0 0 15px rgba(100,100,255,0.5);
  }
  /* Overlay screens */
  .overlay {
    position: fixed; inset: 0;
    display: flex; flex-direction: column;
    align-items: center; justify-content: center;
    z-index: 100;
    background: rgba(0,0,0,0.85);
  }
  .overlay h1 {
    font-size: 42px;
    color: gold;
    text-shadow: 0 0 20px gold;
    margin-bottom: 10px;
  }
  .overlay p {
    color: #ccc;
    font-size: 18px;
    margin-bottom: 30px;
    text-align: center;
    padding: 0 20px;
  }
  .overlay button {
    background: linear-gradient(135deg, #f0a500, #e05000);
    border: none;
    border-radius: 25px;
    color: white;
    font-size: 20px;
    font-weight: bold;
    padding: 14px 40px;
    cursor: pointer;
    box-shadow: 0 5px 20px rgba(240,165,0,0.5);
    transition: transform 0.2s;
  }
  .overlay button:hover { transform: scale(1.05); }
  #nasser-label {
    position: fixed;
    color: #00ffcc;
    font-size: 13px;
    font-weight: bold;
    text-shadow: 0 0 8px #00ffcc;
    pointer-events: none;
    z-index: 5;
    transform: translateX(-50%);
    white-space: nowrap;
  }
  #message {
    position: fixed;
    top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    color: gold;
    font-size: 28px;
    font-weight: bold;
    text-shadow: 0 0 15px gold;
    z-index: 20;
    pointer-events: none;
    opacity: 0;
    transition: opacity 0.3s;
  }
</style>
</head>
