  <button onclick="startGame()">🎮 ابدأ اللعبة</button>
</div>

<!-- Game Over -->
<div class="overlay" id="gameover-screen" style="display:none">
  <h1>💀 انتهت اللعبة</h1>
  <p id="final-score">نقاطك: 0</p>
  <button onclick="restartGame()">🔄 العب مجدداً</button>
</div>

<!-- Win Screen -->
<div class="overlay" id="win-screen" style="display:none">
  <h1>🏆 أحسنت ناصر!</h1>
  <p id="win-msg">أكملت جميع المستويات!</p>
